    const isManager = viewerRole === Role.MANAGER;

    const getStatus = () => {
        // واجهة المنتسب (الموظف)
        if (!isManager) {
            if (report.managerComment && !report.isCommentReadByEmployee) {
                return (
                    <span className="flex items-center gap-1.5 px-3 py-1 text-[10px] font-bold text-blue-700 bg-blue-50 border border-blue-200 rounded-full dark:bg-blue-900/30 dark:text-blue-300 dark:border-blue-800">
                        <span className="w-1.5 h-1.5 bg-blue-500 rounded-full animate-pulse"></span>
                        توجيه جديد
                    </span>
                );
            }
            if (report.managerComment) {
                 return <span className="px-3 py-1 text-[10px] font-bold text-green-700 bg-green-50 border border-green-200 rounded-full dark:bg-green-900/30 dark:text-green-300 dark:border-green-800">تم التوجيه</span>;
            }
            return <span className="px-3 py-1 text-[10px] font-bold text-gray-500 bg-gray-50 border border-gray-100 rounded-full dark:bg-gray-700/50 dark:text-gray-400 dark:border-gray-600">تم الإرسال</span>;
        }

        // واجهة المسؤول (Manager) - التحديث المطلوب
        if (report.managerComment) {
            return (
                <span className="px-3 py-1 text-[10px] font-bold text-amber-700 bg-amber-50 border border-amber-200 rounded-full dark:bg-amber-900/30 dark:text-amber-300 dark:border-amber-800 shadow-sm">
                    تم التعليق
                </span>
            );
        }

        if (!report.isViewedByManager) {
            return (
                <div className="flex items-center gap-2">
                    <span className="relative flex h-2 w-2">
                      <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-blue-400 opacity-75"></span>
                      <span className="relative inline-flex rounded-full h-2 w-2 bg-blue-600"></span>
                    </span>
                    <span className="px-3 py-1 text-[10px] font-bold text-white bg-blue-600 rounded-full shadow-md shadow-blue-500/20">
                        جديد
                    </span>
                </div>
            );
        }

        return (
            <span className="px-3 py-1 text-[10px] font-bold text-gray-500 bg-gray-50 border border-gray-200 rounded-full dark:bg-gray-800 dark:text-gray-400 dark:border-gray-700">
                تمت قراءته
