                : 'border-gray-100 dark:border-gray-700 hover:border-brand-light'
            }`}
            onClick={onClick}
            role="button"
            aria-label={`عرض تقرير ${user.fullName} بتاريخ ${report.date}`}
        >
            <div className="px-5 py-4">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-4">
                        <div className="relative">
                            <Avatar src={user.profilePictureUrl} name={user.fullName} size={48} className="ring-2 ring-white dark:ring-gray-700" />
                            {!report.isViewedByManager && isManager && (
                                <span className="absolute -top-1 -right-1 w-3 h-3 bg-blue-600 border-2 border-white dark:border-gray-800 rounded-full"></span>
                            )}
                        </div>
                        <div>
                            <p className="font-bold text-gray-900 dark:text-gray-100 text-sm md:text-base">{user.fullName}</p>
                            <p className="text-[10px] md:text-xs text-gray-500 dark:text-gray-400 font-medium">{user.jobTitle}</p>
